INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Gestion de la paie et des ressources humaines avec logiciel', 'Formation pratique sur la gestion de la paie et des ressources humaines avec un logiciel spécialisé.', 5, 250000.00, 'entreprise', '2026-03-15', 30, '2026-01-14 12:37:32', '2026-01-14 12:37:32', NULL, E'--- OBJECTIFS ---\n• Maîtriser les bases de la gestion de la paie\n• Utiliser un logiciel RH pour automatiser les processus\n• Assurer la conformité légale et réglementaire\n• Optimiser la gestion des ressources humaines\n• Gagner en efficacité et fiabilité dans le suivi du personnel\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les participants à la gestion de la paie et des ressources humaines, leur apprendre à utiliser un logiciel spécialisé, assurer la conformité légale et optimiser la gestion du personnel.\n\n--- PRÉREQUIS ---\nConnaissances de base en comptabilité ou gestion souhaitées.\n\n--- CONTENU ---\nModule 1 : Introduction à la gestion de la paie et des RH\nModule 2 : Paramétrage et utilisation du logiciel\nModule 3 : Gestion des contrats et des dossiers du personnel\nModule 4 : Calcul et traitement de la paie\nModule 5 : Déclarations sociales et conformité légale\nModule 6 : Suivi des performances et reporting RH\nModule 7 : Atelier pratique – Simulation complète de gestion de paie\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nResponsables RH, gestionnaires de paie, comptables, chefs d’entreprise et toute personne impliquée dans la gestion du personnel.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, ateliers pratiques, études de cas et exercices guidés.\n\n--- SUPPORTS ---\nLogiciel de gestion de paie et RH, modèles de bulletins de paie, tableurs Excel, supports PDF, slides et tutoriels pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
